import { createPrivateTool } from "@decocms/runtime/tools";
import { z } from "zod";
import { renderTranscript, type TranscriptSegment } from "../lib/captions.ts";
import {
  getInnertube,
  parseVideoId,
  wrapInnertubeError,
} from "../lib/innertube.ts";
import type { Env } from "../types/env.ts";
import { mapCaptionTracks } from "./video-details.ts";

export const createListCaptionsTool = (_env: Env) =>
  createPrivateTool({
    id: "YOUTUBE_LIST_CAPTIONS",
    description:
      "List the caption/subtitle tracks available for a YouTube video, including auto-generated (ASR) ones. Use YOUTUBE_GET_TRANSCRIPT to fetch the actual text.",
    inputSchema: z.object({
      videoId: z
        .string()
        .describe("YouTube video id (11 chars) or full video URL"),
    }),
    outputSchema: z.object({
      videoId: z.string(),
      tracks: z.array(
        z.object({
          languageCode: z.string(),
          name: z.string(),
          isAutoGenerated: z.boolean(),
          isTranslatable: z.boolean(),
        }),
      ),
    }),
    execute: async ({ context }) => {
      const videoId = parseVideoId(context.videoId);
      const yt = await getInnertube();
      try {
        const info = await yt.getInfo(videoId);
        return { videoId, tracks: mapCaptionTracks(info) };
      } catch (error) {
        throw wrapInnertubeError(error);
      }
    },
  });

/** Shape of YouTube's timedtext fmt=json3 payload (only what we read). */
interface TimedTextJson3 {
  events?: Array<{
    tStartMs?: number;
    dDurationMs?: number;
    aAppend?: number;
    segs?: Array<{ utf8?: string }>;
  }>;
}

/**
 * Fetches transcript segments straight from the caption track's timedtext
 * URL. youtubei.js's getTranscript() endpoint currently 400s (get_transcript
 * requires panel params YouTube changed), while timedtext base_url keeps
 * working and also supports on-the-fly translation via tlang.
 */
async function fetchSegments(
  baseUrl: string,
  translateTo?: string,
): Promise<TranscriptSegment[]> {
  const url = new URL(baseUrl);
  url.searchParams.set("fmt", "json3");
  if (translateTo) url.searchParams.set("tlang", translateTo);

  const response = await fetch(url, {
    headers: { "User-Agent": "Mozilla/5.0" },
  });
  if (!response.ok) {
    if (translateTo && response.status === 429) {
      throw new Error(
        `YouTube rate-limits machine-translated captions (429 for tlang=${translateTo}). Fetch the original track (omit "language") and translate the text yourself.`,
      );
    }
    throw new Error(`timedtext request failed with status ${response.status}`);
  }
  const data = (await response.json()) as TimedTextJson3;

  return (data.events ?? [])
    .filter((event) => event.segs?.length && !event.aAppend)
    .map((event) => {
      const startMs = event.tStartMs ?? 0;
      return {
        startMs,
        endMs: startMs + (event.dDurationMs ?? 0),
        text: (event.segs ?? [])
          .map((seg) => seg.utf8 ?? "")
          .join("")
          .replace(/\n/g, " ")
          .trim(),
      };
    })
    .filter((segment) => segment.text.length > 0);
}

export const createGetTranscriptTool = (_env: Env) =>
  createPrivateTool({
    id: "YOUTUBE_GET_TRANSCRIPT",
    description:
      "Fetch the transcript/subtitles of a YouTube video (works with auto-generated captions — the ones the official API refuses to export). Can translate to another language when the track is translatable. Output as plain text, SRT, VTT or timed JSON segments.",
    inputSchema: z.object({
      videoId: z
        .string()
        .describe("YouTube video id (11 chars) or full video URL"),
      language: z
        .string()
        .optional()
        .describe(
          'Language code to fetch (e.g. "en", "pt"). Picks the matching caption track, or auto-translates the default track when it is translatable. Defaults to the video\'s default track.',
        ),
      format: z
        .enum(["text", "srt", "vtt", "json"])
        .default("text")
        .describe("Output format (default plain text)"),
    }),
    outputSchema: z.object({
      videoId: z.string(),
      language: z.string().optional(),
      translated: z
        .boolean()
        .describe(
          "Whether the transcript was machine-translated to the requested language",
        ),
      isAutoGenerated: z.boolean(),
      format: z.string(),
      transcript: z
        .string()
        .describe(
          "The rendered transcript (JSON-encoded segments when format=json)",
        ),
      segmentCount: z.number(),
    }),
    execute: async ({ context }) => {
      const videoId = parseVideoId(context.videoId);
      const yt = await getInnertube();

      let info;
      try {
        info = await yt.getInfo(videoId);
      } catch (error) {
        throw wrapInnertubeError(error);
      }

      // deno-lint-ignore no-explicit-any
      const tracks: any[] = info.captions?.caption_tracks ?? [];
      if (tracks.length === 0) {
        throw new Error(
          "This video has no caption tracks (no transcript available).",
        );
      }

      const wanted = context.language?.toLowerCase();
      let track = tracks[0];
      let translateTo: string | undefined;

      if (wanted) {
        const match = tracks.find((candidate) =>
          String(candidate.language_code ?? "")
            .toLowerCase()
            .startsWith(wanted),
        );
        if (match) {
          track = match;
        } else if (track.is_translatable) {
          translateTo = context.language;
        } else {
          throw new Error(
            `No "${context.language}" caption track and the default track is not translatable. Available: ${tracks.map((t) => t.language_code).join(", ")}`,
          );
        }
      }

      const segments = await fetchSegments(String(track.base_url), translateTo);
      if (segments.length === 0) {
        throw new Error("Caption track exists but returned no segments.");
      }

      return {
        videoId,
        language: translateTo ?? String(track.language_code ?? ""),
        translated: Boolean(translateTo),
        isAutoGenerated:
          track.kind === "asr" || String(track.vss_id ?? "").startsWith("a."),
        format: context.format,
        transcript: renderTranscript(segments, context.format),
        segmentCount: segments.length,
      };
    },
  });
